import sys
from collections import deque

class Solution:
    def __init__(self):
        self.q = deque()

    def enqueue(self, x):
        self.q.append(x)

    def dequeue(self):
        if self.q.length() == 0:
            return -1
        else:
            return self.q.popleft()

    def peek(self):
        if self.q.length() == 0:
            return -1
        else:
            return self.q[-1]

def main():
    s = Solution()

    input_str = sys.stdin.readline().strip()
    inputs = list(map(int, input_str.split()))

    for i in range(0, len(inputs), 2):
        op = inputs[i]
        x = inputs[i + 1]

        if op == 1:
            s.enqueue(x)
        elif op == 2:
            print(s.dequeue())
        else:
            print(s.peek())

if __name__ == '__main__':
    main()

