#include <iostream>
#include <deque>

using namespace std;

class Solution {
public:
    deque<int> q;

    void enqueue(int x) {
        q.push_back(x);
    }

    int dequeue() {
        if (q.empty()) {
            return -1;
        } else {
            int front = q.front();
            q.pop_front();
            return front;
        }
    }

    int peek() {
        if (q.empty()) {
            return -1;
        } else {
            return q.back();
        }
    }
};

int main() {
    Solution s;

    int op, x;

    cin >> op >> x;

    while (op != 0) {
        if (op == 1) {
            s.enqueue(x);
        } else if (op == 2) {
            cout << s.dequeue() << endl;
        } else {
            cout << s.peek() << endl;
        }

        cin >> op >> x;
    }

    return 0;
}
